-- Discovery/retrieval additions. Existing queue, modes, metrics, sources and queries remain canonical.
alter table public.research_queries add column if not exists query_family text, add column if not exists provider text, add column if not exists target_evidence_gap text, add column if not exists accepted_source_yield integer not null default 0, add column if not exists provider_cost_usd numeric not null default 0;
alter table public.sources add column if not exists canonical_url text, add column if not exists query_family text, add column if not exists candidate_score numeric, add column if not exists content_hash text, add column if not exists etag text, add column if not exists last_modified text, add column if not exists fetched_at timestamptz, add column if not exists fetch_status integer, add column if not exists extraction_strategy text, add column if not exists extraction_version text default 'v1', add column if not exists extracted_at timestamptz, add column if not exists rejection_reason text;
create unique index if not exists sources_run_canonical_url on public.sources(run_id, canonical_url) where canonical_url is not null;
create table if not exists public.source_registry (domain text primary key, evidence_families text[] not null default '{}', industries text[] not null default '{}', geographies text[] not null default '{}', access_method text not null default 'http', adapter text, quality_tier integer, source_class text not null default 'secondary', commercial_restrictions text, auth_required boolean not null default false, rate_limit_per_minute integer, cache_ttl_seconds integer not null default 86400, extraction_strategy text not null default 'direct_html', robots_restricted boolean not null default false, historical_success_rate numeric, average_relevance numeric, average_extraction_cost numeric, enabled boolean not null default true, updated_at timestamptz not null default now());
create table if not exists public.public_retrieval_cache (canonical_url text primary key, content_hash text not null, text_content text not null, content_type text, etag text, last_modified text, fetched_at timestamptz not null default now(), expires_at timestamptz not null, extraction_version text not null default 'v1', structured_parser_version text, fetch_status integer not null default 200);
create index if not exists public_retrieval_cache_expiry on public.public_retrieval_cache(expires_at);
